const fetch = require('node-fetch');
const baseUrl = process.env.EVAL_API_URL || 'http://eval-api:8504';
const token = process.env.EVAL_API_TOKEN || '';

const modo = (typeof $modo !== 'undefined' && $modo) ? String($modo).trim().toLowerCase() : 'run';
const headers = { 'Content-Type': 'application/json' };
if (token) headers['Authorization'] = `Bearer ${token}`;

let path = '';
let body = {};

if (modo === 'report') {
    path = '/eval/regression/report';
} else if (modo === 'baseline') {
    path = '/eval/regression/baseline';
} else if (modo === 'single') {
    path = '/eval/regression/single';
    const question = (typeof $question !== 'undefined' && $question) ? String($question).trim() : '';
    const expected = (typeof $expected_output !== 'undefined' && $expected_output) ? String($expected_output).trim() : '';
    if (!question || !expected) {
        return JSON.stringify({ error: 'Modo single exige question e expected_output.' });
    }
    body = {
        question,
        expected_output: expected,
        golden_id: (typeof $golden_id !== 'undefined' && $golden_id) ? String($golden_id) : 'adhoc'
    };
} else {
    path = '/eval/regression/run';
    body = { compare_baseline: true };
    if (typeof $limit !== 'undefined' && $limit !== null && $limit !== '') {
        const parsed = parseInt($limit, 10);
        if (!isNaN(parsed)) body.limit = parsed;
    }
    if (typeof $save_baseline !== 'undefined' && $save_baseline !== null && $save_baseline !== '') {
        body.save_baseline = Boolean($save_baseline === true || $save_baseline === 'true' || $save_baseline === 1 || $save_baseline === '1');
    }
}

try {
    const response = await fetch(`${baseUrl}${path}`, {
        method: modo === 'report' ? 'GET' : 'POST',
        headers,
        body: modo === 'report' ? undefined : JSON.stringify(body)
    });
    const text = await response.text();
    if (!response.ok) {
        return JSON.stringify({ error: text, status: response.status });
    }
    return text;
} catch (error) {
    console.error(error);
    return JSON.stringify({ error: String(error) });
}
